#include <stdio.h>
#include <stdlib.h>

int solve(int* a, int n) {
    int maxLen = 0;
    int* sumIndexMap = (int*)calloc(n, sizeof(int));
    int sum = 0;
    for (int i = 0; i < n; i++) {
        sum += a[i];
        if (sum == 0) {
            maxLen = i + 1;
        } else if (sumIndexMap[sum] != 0) {
            maxLen = max(maxLen, i - sumIndexMap[sum]);
        } else {
            sumIndexMap[sum] = i;
        }
    }
    free(sumIndexMap);
    return maxLen;
}

int main() {
    int n;
    scanf("%d", &n);
    int* a = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }
    printf("%d\n", solve(a, n));
    free(a);
    return 0;
}

